problems = []
for topic, items in T:
    for title, slug, diff, sub, desc, examples, constraints, hints, approach, tc, sc in items:
        problems.append({
            "title": title, "slug": slug, "difficulty": diff, "topic": topic,
            "sub_topic": sub, "description": desc, "examples": examples,
            "constraints": constraints, "hints": hints,
            "solution_approach": approach, "time_complexity": tc,
            "space_complexity": sc, "source_url": f"https://leetcode.com/problems/{slug}/",
            "tags": [topic, sub, diff],
        })

out = os.path.join(os.path.dirname(__file__), "seed_problems.json")
with open(out, "w") as f:
    json.dump(problems[:50], f, indent=2)
print(f"Generated {len(problems[:50])} problems to {out}")
